FROM methods 
WHERE method_name = 'getCount';

SELECT COUNT(*)
FROM code_files
WHERE file_size > 10000 AND is_active = 1;

SELECT MIN(UNICODE(issue_type)) AS min_unicode_value
FROM issues
WHERE issue_type = 'unused variable';

SELECT * 
   FROM code_files
   WHERE project_id = 123;

